"use client";

import { useState, useEffect } from "react";
import { toast } from "react-hot-toast";

export default function ProfilePage() {
  const [formData, setFormData] = useState({
    id: "",
    name: "",
    email: "",
    phone_number: "",
    tenth_certificate: null,
    twelfth_certificate: null,
  });

  useEffect(() => {
    const user = JSON.parse(localStorage.getItem("user"));
    if (user?.id) {
      setFormData((prev) => ({ ...prev, id: user.id }));
    }
  }, []);

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleFileChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.files[0] });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!formData.id) {
      toast.error("User ID is missing!");
      return;
    }

    const formDataToSend = new FormData();
    Object.keys(formData).forEach((key) => {
      if (formData[key]) {
        formDataToSend.append(key, formData[key]);
      }
    });

    try {
      toast.loading("Updating profile...");
      const res = await fetch("/api/update-profile", {
        method: "POST",
        body: formDataToSend,
      });

      const data = await res.json();
      toast.dismiss();

      if (res.ok) {
        toast.success("Profile updated successfully!");
        localStorage.setItem("document_verified", "0");
      } else {
        toast.error(data.error || "Something went wrong");
      }
    } catch (error) {
      toast.dismiss();
      toast.error("Failed to update profile");
    }
  };

  return (
    <div className="container mt-5">
      <h2>Update Profile</h2>
      <form onSubmit={handleSubmit}>
        <input type="hidden" name="id" value={formData.id} />
        <div className="mb-3">
          <label className="form-label">Name</label>
          <input
            type="text"
            name="name"
            className="form-control"
            value={formData.name}
            onChange={handleChange}
            required
          />
        </div>
        <div className="mb-3">
          <label className="form-label">Email</label>
          <input
            type="email"
            name="email"
            className="form-control"
            value={formData.email}
            onChange={handleChange}
            required
          />
        </div>
        <div className="mb-3">
          <label className="form-label">Phone Number</label>
          <input
            type="text"
            name="phone_number"
            className="form-control"
            value={formData.phone_number}
            onChange={handleChange}
            required
          />
        </div>
        <Form.Group className="mb-3" controlId="formProgram">
          <Form.Label>Select Program</Form.Label>
          <Form.Select
            name="program_id"
            value={formData.program_id}
            onChange={handleChange}
          >
            <option value="">Select a program</option>
            {program
              ? program.map((program) => (
                  <option key={program.id} value={program.id}>
                    {program.name}
                  </option>
                ))
              : null}
          </Form.Select>
        </Form.Group>

        <Form.Group className="mb-3" controlId="formUniversity">
          <Form.Label>Select University</Form.Label>
          <Form.Select
            name="university_id"
            value={formData.university_id}
            onChange={handleChange}
          >
            <option value="">Select a university</option>
            {university
              ? university.map((university) => (
                  <option key={university.id} value={university.id}>
                    {university.name}
                  </option>
                ))
              : null}
          </Form.Select>
        </Form.Group>
        <div className="mb-3">
          <label className="form-label">Tenth Certificate</label>
          <input
            type="file"
            name="tenth_certificate"
            className="form-control"
            onChange={handleFileChange}
            accept="application/pdf, image/*"
          />
        </div>
        <div className="mb-3">
          <label className="form-label">Twelfth Certificate</label>
          <input
            type="file"
            name="twelfth_certificate"
            className="form-control"
            onChange={handleFileChange}
            accept="application/pdf, image/*"
          />
        </div>
        <button type="submit" className="btn btn-primary">
          Update Profile
        </button>
      </form>
    </div>
  );
}
